import{_ as a,o as n,c as l,a2 as o}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Cross Compilation","description":"Cross-compiling the agent for Linux x86_64, Linux aarch64, and macOS targets using cross, handling platform-specific dependencies and linking challenges.","frontmatter":{"title":"Cross Compilation","description":"Cross-compiling the agent for Linux x86_64, Linux aarch64, and macOS targets using cross, handling platform-specific dependencies and linking challenges."},"headers":[],"relativePath":"learn/project/15-production-polish/06-cross-compilation.md","filePath":"learn/project/15-production-polish/06-cross-compilation.md"}'),t={name:"learn/project/15-production-polish/06-cross-compilation.md"};function e(p,s,c,r,i,y){return n(),l("div",null,[...s[0]||(s[0]=[o(`<h1 id="cross-compilation" tabindex="-1">Cross Compilation <a class="header-anchor" href="#cross-compilation" aria-label="Permalink to &quot;Cross Compilation&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to set up cross-compilation toolchains for Linux and macOS targets from any host platform</li><li>How to handle platform-specific dependencies like OpenSSL and native TLS libraries</li><li>Techniques for CI-based cross-compilation that produces verified binaries for each release</li></ul></blockquote><p>Your users run Linux, macOS, and Windows on both x86_64 and ARM architectures. Building only for your development machine means leaving the majority of your potential users without a simple installation path. Cross-compilation lets you produce binaries for all target platforms from a single machine -- or, more practically, from a CI pipeline. Rust has excellent cross-compilation support, and with the right setup, you can target six or more platforms from one GitHub Actions workflow.</p><h2 id="understanding-rust-targets" tabindex="-1">Understanding Rust Targets <a class="header-anchor" href="#understanding-rust-targets" aria-label="Permalink to &quot;Understanding Rust Targets&quot;">​</a></h2><p>Rust identifies platforms with target triples: <code>&lt;arch&gt;-&lt;vendor&gt;-&lt;os&gt;-&lt;env&gt;</code>. Here are the targets that matter most for a CLI tool:</p><table tabindex="0"><thead><tr><th>Target Triple</th><th>Platform</th><th>Notes</th></tr></thead><tbody><tr><td><code>x86_64-unknown-linux-gnu</code></td><td>Linux x86_64 (glibc)</td><td>Most common server/desktop Linux</td></tr><tr><td><code>x86_64-unknown-linux-musl</code></td><td>Linux x86_64 (static)</td><td>Fully static binary, works everywhere</td></tr><tr><td><code>aarch64-unknown-linux-gnu</code></td><td>Linux ARM64</td><td>AWS Graviton, Raspberry Pi 4</td></tr><tr><td><code>aarch64-unknown-linux-musl</code></td><td>Linux ARM64 (static)</td><td>Static binary for ARM Linux</td></tr><tr><td><code>x86_64-apple-darwin</code></td><td>macOS Intel</td><td>Older Macs</td></tr><tr><td><code>aarch64-apple-darwin</code></td><td>macOS Apple Silicon</td><td>M1/M2/M3/M4 Macs</td></tr><tr><td><code>x86_64-pc-windows-msvc</code></td><td>Windows x86_64</td><td>Windows desktop</td></tr></tbody></table><p>Install additional targets with rustup:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Add a target</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> target</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> target</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> aarch64-unknown-linux-gnu</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># List installed targets</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> target</span><span style="color:#A6E3A1;"> list</span><span style="color:#A6E3A1;"> --installed</span></span></code></pre></div><h2 id="the-tls-challenge" tabindex="-1">The TLS Challenge <a class="header-anchor" href="#the-tls-challenge" aria-label="Permalink to &quot;The TLS Challenge&quot;">​</a></h2><p>The biggest cross-compilation hurdle for HTTP-heavy applications like your agent is TLS. The <code>reqwest</code> crate (which you use for API calls) needs a TLS implementation. You have two options:</p><p><strong>Option 1: <code>rustls</code> (recommended for cross-compilation)</strong></p><p><code>rustls</code> is a pure-Rust TLS implementation. It requires no system libraries, making cross-compilation trivial.</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">dependencies</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">reqwest </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.12&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> default-features </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> false</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;json&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;stream&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;rustls-tls&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span></code></pre></div><p><strong>Option 2: <code>native-tls</code></strong></p><p>Uses the platform&#39;s native TLS library (OpenSSL on Linux, Security.framework on macOS, SChannel on Windows). Better compatibility with corporate proxies but harder to cross-compile.</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">dependencies</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">reqwest </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.12&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;json&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;stream&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;native-tls&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span></code></pre></div><p>For a CLI tool distributed as a binary, <code>rustls</code> is the pragmatic choice. It eliminates a whole class of cross-compilation problems.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Python sidesteps cross-compilation entirely for most use cases -- you distribute source code (or wheels), and the target machine&#39;s Python interpreter handles platform differences. When you do need platform-specific Python packages (like those with C extensions), you encounter similar pain points: linking against system libraries, compatibility across glibc versions, and the manylinux standards. Rust&#39;s advantage is that once you get cross-compilation working, you produce a single static binary with zero runtime dependencies.</p></div><h2 id="using-cross-for-easy-cross-compilation" tabindex="-1">Using cross for Easy Cross-Compilation <a class="header-anchor" href="#using-cross-for-easy-cross-compilation" aria-label="Permalink to &quot;Using cross for Easy Cross-Compilation&quot;">​</a></h2><p>The <code>cross</code> tool uses Docker containers pre-configured with the right toolchains for each target. It is a drop-in replacement for <code>cargo</code> that handles the cross-compilation environment automatically.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install cross</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> cross</span><span style="color:#A6E3A1;"> --git</span><span style="color:#A6E3A1;"> https://github.com/cross-rs/cross</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Build for Linux x86_64 (musl for static linking)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cross</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Build for Linux ARM64</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cross</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> aarch64-unknown-linux-gnu</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Run tests on the target platform (inside the Docker container)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cross</span><span style="color:#A6E3A1;"> test</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span></code></pre></div><p>For custom build requirements, create a <code>Cross.toml</code> in your project root:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">build.env</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">passthrough </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;ANTHROPIC_API_KEY&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;AGENT_VERSION&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">target.x86_64-unknown-linux-musl</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">image </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;ghcr.io/cross-rs/x86_64-unknown-linux-musl:main&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">target.aarch64-unknown-linux-gnu</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">image </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;ghcr.io/cross-rs/aarch64-unknown-linux-gnu:main&quot;</span></span></code></pre></div><p>The <code>passthrough</code> setting forwards environment variables into the Docker container, which is necessary if your build script needs API keys or version information.</p><h2 id="building-macos-universal-binaries" tabindex="-1">Building macOS Universal Binaries <a class="header-anchor" href="#building-macos-universal-binaries" aria-label="Permalink to &quot;Building macOS Universal Binaries&quot;">​</a></h2><p>If you are on macOS, you can build a universal binary that works on both Intel and Apple Silicon Macs:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install both targets</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> target</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> x86_64-apple-darwin</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> target</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> aarch64-apple-darwin</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Build for both architectures</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-apple-darwin</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> aarch64-apple-darwin</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Combine into a universal binary with lipo</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">lipo</span><span style="color:#A6E3A1;"> -create</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    target/x86_64-apple-darwin/release/agent</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    target/aarch64-apple-darwin/release/agent</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    -output</span><span style="color:#A6E3A1;"> target/release/agent-universal</span></span></code></pre></div><p>The universal binary is roughly twice the size of a single-architecture binary, but it provides a seamless experience for all macOS users.</p><h2 id="platform-specific-code" tabindex="-1">Platform-Specific Code <a class="header-anchor" href="#platform-specific-code" aria-label="Permalink to &quot;Platform-Specific Code&quot;">​</a></h2><p>Sometimes you need platform-specific behavior. Use Rust&#39;s conditional compilation:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">/// Get the default config directory for the current platform.</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> default_config_dir</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">path</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">PathBuf</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">target_os </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;linux&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CBA6F7;"> let</span><span style="color:#F9E2AF;font-style:italic;"> Ok</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">xdg</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;XDG_CONFIG_HOME&quot;</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">path</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">PathBuf</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">xdg</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">join</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;agent&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#F9E2AF;">        dirs</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">home_dir</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">map</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">h</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> h</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">join</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;.config&quot;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">join</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;agent&quot;</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">unwrap_or_else</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">||</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">path</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">PathBuf</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;.&quot;</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">target_os </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;macos&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#F9E2AF;">        dirs</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">home_dir</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">map</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">h</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> h</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">join</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Library&quot;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">join</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Application Support&quot;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">join</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;agent&quot;</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">unwrap_or_else</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">||</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">path</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">PathBuf</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;.&quot;</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">target_os </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;windows&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#F9E2AF;">        dirs</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">config_dir</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">map</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">c</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> c</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">join</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;agent&quot;</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">unwrap_or_else</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">||</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">path</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">PathBuf</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;.&quot;</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// Get the appropriate shell for the current platform.</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> default_shell</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#9399B2;">&#39;</span><span style="color:#89B4FA;font-style:italic;">static</span><span style="color:#F9E2AF;font-style:italic;"> str</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">target_os </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;windows&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;cmd.exe&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">not</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">target_os </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;windows&quot;</span><span style="color:#9399B2;">))]</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;/bin/sh&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h2 id="static-linking-with-musl" tabindex="-1">Static Linking with musl <a class="header-anchor" href="#static-linking-with-musl" aria-label="Permalink to &quot;Static Linking with musl&quot;">​</a></h2><p>For maximum portability on Linux, use musl instead of glibc. The resulting binary has zero dynamic library dependencies and runs on any Linux distribution, regardless of glibc version.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Build a fully static binary</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cross</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Verify it is statically linked</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">file</span><span style="color:#A6E3A1;"> target/x86_64-unknown-linux-musl/release/agent</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Output: ELF 64-bit LSB executable, x86-64, statically linked...</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Check dynamic dependencies (should show none)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ldd</span><span style="color:#A6E3A1;"> target/x86_64-unknown-linux-musl/release/agent</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Output: not a dynamic executable</span></span></code></pre></div><p>Static musl binaries are ideal for Docker containers based on <code>scratch</code> or <code>alpine</code>:</p><div class="language-dockerfile"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">FROM</span><span style="color:#CDD6F4;"> scratch</span></span>
<span class="line"><span style="color:#CBA6F7;">COPY</span><span style="color:#CDD6F4;"> target/x86_64-unknown-linux-musl/release/agent /agent</span></span>
<span class="line"><span style="color:#CBA6F7;">ENTRYPOINT</span><span style="color:#CDD6F4;"> [</span><span style="color:#A6E3A1;">&quot;/agent&quot;</span><span style="color:#CDD6F4;">]</span></span></code></pre></div><p>This produces a Docker image that contains only your binary -- no operating system, no shell, no libraries. The image size equals your binary size.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code distributes as an npm package that bundles platform-specific binaries, avoiding the cross-compilation problem by leveraging npm&#39;s platform detection. OpenCode, being written in Go, benefits from Go&#39;s built-in cross-compilation support (<code>GOOS=linux GOARCH=arm64 go build</code>). Rust&#39;s cross-compilation story requires more setup, but the resulting binaries are typically smaller and faster than Go equivalents, and the static musl approach eliminates the glibc version compatibility issues that plague many Linux tools.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Use <code>rustls</code> instead of <code>native-tls</code> in reqwest to eliminate the most common cross-compilation blocker -- linking against platform-specific TLS libraries.</li><li>Target the six major platforms (Linux x86_64, Linux ARM64, macOS Intel, macOS Apple Silicon, each in glibc and musl variants) to cover the vast majority of your user base.</li><li>Use the <code>cross</code> tool for Docker-based cross-compilation that handles toolchains automatically -- it is a drop-in replacement for <code>cargo</code> that just works.</li><li>Build musl-linked static binaries for Linux to produce executables with zero dynamic dependencies that run on any Linux distribution regardless of glibc version.</li><li>Use <code>#[cfg(target_os = &quot;...&quot;)]</code> for platform-specific code paths like config directory locations and default shell selection, keeping the rest of your codebase platform-agnostic.</li></ul>`,40)])])}const A=a(t,[["render",e]]);export{d as __pageData,A as default};
